parameters.jsCode:
let text = $json.content[0].text.trim();
if (text.startsWith('```')) { text = text.split('```')[1].replace(/^json/, '').trim(); }
const p = JSON.parse(text);
const mimeMap = { presentation: 'application/vnd.google-apps.presentation', spreadsheet: 'application/vnd.google-apps.spreadsheet', document: 'application/vnd.google-apps.document', pdf: 'application/pdf' };
let clauses = (p.keywords || []).map(k => `fullText contains '${k}'`);
if (mimeMap[p.mime_hint]) clauses.push(`mimeType = '${mimeMap[p.mime_hint]}'`);
return { json: { driveQuery: clauses.join(' and ') } };
